#!/bin/bash
# This file was generated by Cursor AI on 2026-04-29.

set -euo pipefail

usage() {
    echo "Usage: $0 [timeout] [memout] [num-jobs]" >&2
    exit 1
}

if [ "$#" -gt 3 ]; then
    usage
fi

TIMEOUT="${1:-3600}"
MEMOUT="${2:-64000}"
NUM_JOBS="${3:-20}"

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"

"$SCRIPT_DIR/benchmark.sh" \
  --input-file-list "/opt/benchmarks/benchmarks.txt" \
  --output-json "/opt/benchmarks/results/control.json" \
  --control \
  --timeout "$TIMEOUT" \
  --memout "$MEMOUT" \
  --num-jobs "$NUM_JOBS" \
  --extraction-method "optimal" \
  --multi-arity \
  --assoc-comm
